function i(r){if(!r)return"";const e=r.replace(/[\s:-]/g,"").toUpperCase();if(/^[0-9A-F]{8}$/.test(e))return e;if(/^[0-9A-F]+$/.test(e)&&/[A-F]/.test(e)){let t=e;for(t.length%2!==0&&(t="0"+t);t.length<8;)t="0"+t;return(t.match(/.{2}/g)||[]).reverse().join("")}if(/^\d+$/.test(e)){let n=BigInt(e).toString(16).toUpperCase();for(n.length%2!==0&&(n="0"+n);n.length<8;)n="0"+n;return(n.match(/.{2}/g)||[]).reverse().join("")}return e}export{i as c};
